// ── Bot logic mirrored from n8n/lib/bot-logic.js (keep in sync) ──
function pickLatestTid(pointer,registry){if(pointer&&typeof pointer==='string')return pointer;let best=null,bo=-Infinity;for(const [id,t] of Object.entries(registry||{})){if(!t||id.startsWith('_'))continue;const o=typeof t.order==='number'?t.order:0;if(o>bo){best=id;bo=o;}}return best;}
function selectAnnouncements(scores){return Object.entries(scores||{}).filter(([,s])=>s&&s.winner_nickname&&s.notified!==true).map(([matchId,s])=>Object.assign({matchId},s));}
function announcementText(s,title){const t=title||s.tournament_id||'the tournament';const suf=s.result?' ('+s.result+')':'';return '🏆 '+s.winner_nickname+' beat '+s.loser_nickname+' in '+t+suf+'.';}

const cfg = $json;
const q = cfg.fbAuth || '';

// Poll the active tournament's scores.
let tid = await this.helpers.httpRequest({ url: cfg.fbUrl+'/latest_tournament.json'+q, json:true }).catch(()=>null);
if(!(tid && typeof tid==='string')){ const reg = await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments.json'+q, json:true }).catch(()=>({})); tid = pickLatestTid(null, reg||{}); }
if(!tid){ return [{ json: { announced: 0, note: 'no active tournament' } }]; }

const title = await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments/'+tid+'/title.json'+q, json:true }).catch(()=>tid);
const scores = await this.helpers.httpRequest({ url: cfg.fbUrl+'/tournaments/'+tid+'/scores.json'+q, json:true }).catch(()=>({}));
const pending = selectAnnouncements(scores);

let announced = 0;
for(const s of pending){
  const message = announcementText(s, title);
  if(cfg.whapiToken){ await this.helpers.httpRequest({ method:'POST', url: cfg.whapiBase+'/messages/text', headers:{ Authorization:'Bearer '+cfg.whapiToken }, body:{ to: cfg.waGroupId, body: message }, json:true }); }
  // Mark notified so it is not announced again (corrections reset it to false).
  await this.helpers.httpRequest({ method:'PATCH', url: cfg.fbUrl+'/tournaments/'+tid+'/scores/'+s.matchId+'.json'+q, body:{ notified: true }, json:true });
  announced++;
}
return [{ json: { tid, announced } }];
